sql:
SELECT min_stock
FROM inventory_thresholds
WHERE component_id = 1;

external_knowledge:
- "running low" refers to the current stock level being below the reorder point; 
- "highly-rated vendors" are those with a rating of 4 or higher; 
- "critically low" means an average stock level below 50.

sql:
SELECT component_id
FROM components
WHERE stock < reorder_point;
